module div_16bit(
    input [15:0] dividend,
    input [7:0] divisor,
    output reg [15:0] quotient,
    output reg [15:0] remainder
);

    always @(*) begin
        if (dividend[15:8] >= divisor) begin
            quotient = 16'h0001;
            remainder = dividend[15:8] - divisor;
        end else begin
            quotient = 16'h0000;
            remainder = dividend[15:8];
        end
    end

endmodule
